package main

import (
	"html/template"
	"log"
	"net/http"
)

type Comment struct {
	Author string
	Body   template.HTML
}

var comments = []Comment{
	{
		Author: "Alice",
		Body:   template.HTML("Hello, <b>world</b>!"),
	},
	{
		Author: "Bob",
		Body:   template.HTML("I like <i>Go</i> and <a href=\"https://go.dev\">this site</a>."),
	},
	{
		Author: "Carol",
		Body:   template.HTML("Nice post!<br>Thanks for sharing."),
	},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!doctype html>
<html lang="en">
<head>
	<meta charset="utf-8">
	<title>User Comments</title>
	<style>
		body { font-family: sans-serif; margin: 2rem; }
		.comment { padding: 1rem 0; border-bottom: 1px solid #ddd; }
		.author { font-weight: bold; margin-bottom: 0.5rem; }
		.body { color: #333; }
	</style>
</head>
<body>
	<h1>User Comments</h1>
	{{range .}}
	<div class="comment">
		<div class="author">{{.Author}}</div>
		<div class="body">{{.Body}}</div>
	</div>
	{{else}}
	<p>No comments yet.</p>
	{{end}}
</body>
</html>
`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	if r.URL.Path != "/comments" {
		http.NotFound(w, r)
		return
	}

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, "failed to render comments", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	log.Println("listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}